const listLearningEnrollments = `-- name: ListLearningEnrollments :many
SELECT
    e.id, e.tenant_id, e.course_id, e.path_id, e.worker_profile_id, e.assignment_source, e.status, e.nominated_by, e.assigned_by, e.due_date, e.started_at, e.completed_at, e.score, e.certificate_url, e.certificate_file_name, e.certificate_content_type, e.notes, e.metadata, e.inactive, e.created_at, e.created_by, e.updated_at, e.updated_by,
    c.title AS course_title,
    c.code AS course_code,
    c.course_type,
    c.ai_readiness,
    c.mandatory,
    p.title AS path_title,
    wp.display_name AS worker_display_name,
    wp.worker_code
FROM hrms.learning_enrollments e
JOIN hrms.learning_courses c ON c.tenant_id = e.tenant_id AND c.id = e.course_id AND NOT c.inactive
LEFT JOIN hrms.learning_paths p ON p.tenant_id = e.tenant_id AND p.id = e.path_id AND NOT p.inactive
JOIN hrms.worker_profiles wp ON wp.tenant_id = e.tenant_id AND wp.id = e.worker_profile_id AND NOT wp.inactive
WHERE e.tenant_id = $1
  AND ($2::uuid IS NULL OR e.worker_profile_id = $2::uuid)
  AND ($3::uuid IS NULL OR e.course_id = $3::uuid)
  AND ($4::text IS NULL OR e.status = $4::text)
  AND ($5::text IS NULL OR e.assignment_source = $5::text)
  AND (
      $6::text IS NULL
      OR c.title ILIKE '%' || $6::text || '%'
      OR wp.display_name ILIKE '%' || $6::text || '%'
      OR wp.worker_code ILIKE '%' || $6::text || '%'
  )
  AND NOT e.inactive
ORDER BY CASE e.status WHEN 'overdue' THEN 1 WHEN 'assigned' THEN 2 WHEN 'nominated' THEN 3 WHEN 'in_progress' THEN 4 ELSE 5 END,
         e.due_date ASC NULLS LAST,
         e.updated_at DESC
LIMIT $8 OFFSET $7
`

