const listLearningPaths = `-- name: ListLearningPaths :many
SELECT
    p.id, p.tenant_id, p.code, p.title, p.description, p.path_type, p.target_role, p.skill_id, p.ai_readiness, p.is_active, p.metadata, p.inactive, p.created_at, p.created_by, p.updated_at, p.updated_by,
    s.name AS skill_name,
    COUNT(pc.id)::int AS course_count,
    COALESCE(SUM(c.duration_minutes) FILTER (WHERE NOT c.inactive), 0)::int AS total_minutes
FROM hrms.learning_paths p
LEFT JOIN hrms.skills s ON s.id = p.skill_id AND NOT s.inactive
LEFT JOIN hrms.learning_path_courses pc ON pc.tenant_id = p.tenant_id AND pc.path_id = p.id AND NOT pc.inactive
LEFT JOIN hrms.learning_courses c ON c.tenant_id = p.tenant_id AND c.id = pc.course_id AND NOT c.inactive
WHERE p.tenant_id = $1
  AND ($2::text IS NULL OR p.path_type = $2::text)
  AND ($3::uuid IS NULL OR p.skill_id = $3::uuid)
  AND ($4::boolean IS NULL OR p.ai_readiness = $4::boolean)
  AND ($5::boolean IS NULL OR p.is_active = $5::boolean)
  AND (
      $6::text IS NULL
      OR p.code ILIKE '%' || $6::text || '%'
      OR p.title ILIKE '%' || $6::text || '%'
      OR p.description ILIKE '%' || $6::text || '%'
  )
  AND NOT p.inactive
GROUP BY p.id, s.name
ORDER BY p.ai_readiness DESC, p.title ASC
LIMIT $8 OFFSET $7
`

