const listLearningRecommendations = `-- name: ListLearningRecommendations :many
SELECT
    r.id, r.tenant_id, r.worker_profile_id, r.skill_id, r.course_id, r.path_id, r.source_type, r.reason, r.priority, r.confidence_score, r.status, r.metadata, r.inactive, r.created_at, r.created_by, r.updated_at, r.updated_by,
    wp.display_name AS worker_display_name,
    wp.worker_code,
    s.name AS skill_name,
    c.title AS course_title,
    p.title AS path_title
FROM hrms.learning_recommendations r
LEFT JOIN hrms.worker_profiles wp ON wp.tenant_id = r.tenant_id AND wp.id = r.worker_profile_id AND NOT wp.inactive
LEFT JOIN hrms.skills s ON s.id = r.skill_id AND NOT s.inactive
LEFT JOIN hrms.learning_courses c ON c.tenant_id = r.tenant_id AND c.id = r.course_id AND NOT c.inactive
LEFT JOIN hrms.learning_paths p ON p.tenant_id = r.tenant_id AND p.id = r.path_id AND NOT p.inactive
WHERE r.tenant_id = $1
  AND ($2::uuid IS NULL OR r.worker_profile_id = $2::uuid)
  AND ($3::uuid IS NULL OR r.skill_id = $3::uuid)
  AND ($4::text IS NULL OR r.source_type = $4::text)
  AND ($5::text IS NULL OR r.status = $5::text)
  AND (
      $6::text IS NULL
      OR r.reason ILIKE '%' || $6::text || '%'
      OR wp.display_name ILIKE '%' || $6::text || '%'
      OR s.name ILIKE '%' || $6::text || '%'
      OR c.title ILIKE '%' || $6::text || '%'
  )
  AND NOT r.inactive
ORDER BY CASE r.priority WHEN 'urgent' THEN 1 WHEN 'high' THEN 2 WHEN 'medium' THEN 3 ELSE 4 END,
         r.created_at DESC
LIMIT $8 OFFSET $7
`

